import{_ as t,a,b as d,c as s}from"./chunks/查询额度成功的卡牌.2KCF7h3O.js";import{_ as l,o as i,c as n,a2 as o}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"افزودن S3 Channel","description":"","frontmatter":{},"headers":[],"relativePath":"fa/upload/s3.md","filePath":"fa/upload/s3.md","lastUpdated":1781962217000}'),c={name:"fa/upload/s3.md"};function r(p,e,h,u,m,b){return i(),n("div",null,[...e[0]||(e[0]=[o(`<h1 id="افزودن-s3-channel" tabindex="-1">افزودن S3 Channel <a class="header-anchor" href="#افزودن-s3-channel" aria-label="Permalink to &quot;افزودن S3 Channel&quot;">​</a></h1><h2 id="چه-زمانی-مناسب-است" tabindex="-1">چه زمانی مناسب است <a class="header-anchor" href="#چه-زمانی-مناسب-است" aria-label="Permalink to &quot;چه زمانی مناسب است&quot;">​</a></h2><p>S3 channel را زمانی استفاده کنید که:</p><ul><li>می‌خواهید هر سرویس object storage سازگار با S3 را وصل کنید؛ مثل Cloudflare R2، Backblaze B2، MinIO، AWS S3 یا provider سازگار دیگر.</li><li>مدل استاندارد S3 را ترجیح می‌دهید: <code>Endpoint</code>، Access Key و Secret Key.</li><li>نمی‌خواهید از native Cloudflare R2 binding channel استفاده کنید، یا storage provider شما Cloudflare R2 نیست.</li></ul><h2 id="پیش-از-شروع-چه-چیزهایی-لازم-است" tabindex="-1">پیش از شروع چه چیزهایی لازم است <a class="header-anchor" href="#پیش-از-شروع-چه-چیزهایی-لازم-است" aria-label="Permalink to &quot;پیش از شروع چه چیزهایی لازم است&quot;">​</a></h2><table tabindex="0"><thead><tr><th>مورد</th><th>کاربرد</th></tr></thead><tbody><tr><td>S3 Endpoint</td><td>endpoint مربوط به S3 API سرویس object storage.</td></tr><tr><td>Bucket name</td><td>bucket که files در آن ذخیره می‌شوند.</td></tr><tr><td>Region</td><td>storage region. برای Cloudflare R2 معمولاً <code>auto</code> است.</td></tr><tr><td>Access Key ID</td><td>S3 access key ID.</td></tr><tr><td>Secret Access Key</td><td>S3 secret access key.</td></tr><tr><td>CDN domain</td><td>custom domain اختیاری برای دسترسی به files.</td></tr></tbody></table><p>نمونه برای Cloudflare R2 از طریق S3 API:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Endpoint: https://your-account-id.r2.cloudflarestorage.com</span></span>
<span class="line"><span>Bucket: your-r2-bucket-name</span></span>
<span class="line"><span>Region: auto</span></span>
<span class="line"><span>Access Key ID: copied from the Cloudflare R2 API token</span></span>
<span class="line"><span>Secret Access Key: copied from the Cloudflare R2 API token</span></span></code></pre></div><h2 id="کجا-اضافه-کنیم" tabindex="-1">کجا اضافه کنیم <a class="header-anchor" href="#کجا-اضافه-کنیم" aria-label="Permalink to &quot;کجا اضافه کنیم&quot;">​</a></h2><ol><li>System Settings را باز کنید.</li><li>وارد Upload Settings شوید.</li><li>از گوشه بالا سمت راست Add Channel را بزنید.</li><li><code>S3</code> را انتخاب کنید.</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>کاربرد</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>نام قابل‌تشخیص برای این S3 channel، مثل <code>s3test</code> یا <code>R2-S3</code>.</td><td>Yes</td></tr><tr><td>Enable channel</td><td>مشخص می‌کند این channel در upload selection شرکت کند یا نه.</td><td>Recommended</td></tr><tr><td>Endpoint</td><td>endpoint کامل S3 service همراه <code>https://</code>.</td><td>Yes</td></tr><tr><td>Custom CDN domain</td><td>اختیاری. اگر تنظیم شود، generated file links این domain را ترجیح می‌دهند.</td><td>No</td></tr><tr><td>Bucket name</td><td>bucket name، مثل <code>s3test</code> یا <code>img-r2</code>.</td><td>Yes</td></tr><tr><td>Bucket region</td><td>Region. برای Cloudflare R2 معمولاً <code>auto</code>.</td><td>Yes</td></tr><tr><td>Access Key ID</td><td>S3 access key ID.</td><td>Yes</td></tr><tr><td>Secret Access Key</td><td>S3 secret access key.</td><td>Yes</td></tr><tr><td>Path-style access</td><td>compatibility switch. پیش‌فرض off است. بعضی MinIO، OpenList یا self-hosted S3 services ممکن است به آن نیاز داشته باشند.</td><td>No</td></tr><tr><td>Quota limit</td><td>مشخص می‌کند این S3 channel بر اساس capacity در upload selection شرکت کند یا نه.</td><td>No</td></tr><tr><td>Capacity limit</td><td>پس از enable شدن quota limit لازم است، مثل <code>10 GB</code>.</td><td>Required when quota limit is enabled</td></tr><tr><td>Threshold</td><td>وقتی usage به این درصد رسید، نوشتن متوقف می‌شود، مثل <code>90%</code>.</td><td>Required when quota limit is enabled</td></tr><tr><td>Remark</td><td>یادداشت برای نگهداری خودتان.</td><td>No</td></tr></tbody></table><h2 id="ساخت-cloudflare-r2-s3-api-keys" tabindex="-1">ساخت Cloudflare R2 S3 API Keys <a class="header-anchor" href="#ساخت-cloudflare-r2-s3-api-keys" aria-label="Permalink to &quot;ساخت Cloudflare R2 S3 API Keys&quot;">​</a></h2><ol><li>Cloudflare Dashboard را باز کنید.</li><li>به <code>R2 Object Storage</code> بروید.</li><li><code>Manage R2 API Tokens</code> یا entry مدیریت API token را پیدا کنید.</li></ol><p>![R2 API token entry](../../image/upload/s3/r2 api token入口.png)</p><ol start="4"><li>یک R2 API token بسازید که به target bucket دسترسی داشته باشد.</li></ol><p><img src="`+t+'" alt="Create an account API token" loading="lazy"></p><ol start="5"><li><code>Access Key ID</code> و <code>Secret Access Key</code> ساخته‌شده را copy کنید.</li></ol><p><img src="'+a+'" alt="Copy the token values" loading="lazy"></p><ol start="6"><li>به صفحه R2 bucket برگردید و bucket name را confirm کنید.</li><li>S3 API endpoint مربوط به account را یادداشت کنید. معمولاً شبیه این است:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-account-id.r2.cloudflarestorage.com</span></span></code></pre></div><h2 id="مراحل-setup" tabindex="-1">مراحل setup <a class="header-anchor" href="#مراحل-setup" aria-label="Permalink to &quot;مراحل setup&quot;">​</a></h2><ol><li>Upload Settings را باز کنید.</li><li>Add Channel را بزنید.</li><li><code>S3</code> را انتخاب کنید.</li><li>یک channel name قابل‌تشخیص وارد کنید، مثل <code>s3test</code>.</li><li>S3 API endpoint را در <code>Endpoint</code> وارد کنید.</li><li>اگر custom CDN دارید، آن را در <code>Custom CDN domain</code> وارد کنید؛ در غیر این صورت خالی بگذارید.</li><li>bucket name را وارد کنید.</li><li>region را وارد کنید. برای مثال Cloudflare R2 از <code>auto</code> استفاده کنید.</li><li>Access Key ID و Secret Access Key را وارد کنید.</li><li>path-style access را off نگه دارید، مگر اینکه provider صریحاً آن را لازم بداند.</li><li>اگر capacity control می‌خواهید، quota limit را enable کنید و capacity limit و threshold را وارد کنید.</li><li>Save را بزنید.</li></ol><p><img src="'+d+'" alt="Add S3 configuration" loading="lazy"></p><h2 id="روش-بررسی" tabindex="-1">روش بررسی <a class="header-anchor" href="#روش-بررسی" aria-label="Permalink to &quot;روش بررسی&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>روش بررسی</th></tr></thead><tbody><tr><td>Channel card appears</td><td>پس از Save، Upload Settings باید S3 channel card را نشان دهد.</td></tr><tr><td>Channel is enabled</td><td>switch بالای card باید روشن بماند.</td></tr><tr><td>Key fields are saved</td><td>detail view باید Endpoint، Bucket، Region، path-style access و fields مربوطه را نشان دهد.</td></tr><tr><td>Upload works</td><td>یک test image upload کنید و مطمئن شوید object در target bucket ایجاد شده است.</td></tr><tr><td>Link opens</td><td>image link برگشتی پس از upload باید عادی باز شود.</td></tr><tr><td>Capacity display works</td><td>اگر quota limit enabled باشد، card باید used capacity و configured limit را نشان دهد.</td></tr></tbody></table><p>آمار capacity در S3 از local file records داخل ImgBed محاسبه می‌شود، نه از query لحظه‌ای provider bucket. پس از save کردن S3 configuration، system quota ledger را از current D1 records دوباره محاسبه می‌کند.</p><p><img src="'+s+`" alt="Quota query succeeded" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="آیا-path-style-access-را-enable-کنم؟" tabindex="-1">آیا path-style access را enable کنم؟ <a class="header-anchor" href="#آیا-path-style-access-را-enable-کنم؟" aria-label="Permalink to &quot;آیا path-style access را enable کنم؟&quot;">​</a></h3><p>معمولاً نه.</p><p>فقط وقتی enable کنید که provider سازگار با S3 شما virtual-hosted-style URLs را پشتیبانی نمی‌کند، یا documentation provider صریحاً path-style access را لازم می‌داند.</p><h3 id="cdn-domain-برای-چیست؟" tabindex="-1">CDN domain برای چیست؟ <a class="header-anchor" href="#cdn-domain-برای-چیست؟" aria-label="Permalink to &quot;CDN domain برای چیست؟&quot;">​</a></h3><p>اگر جلوی bucket یک CDN یا custom access domain گذاشته‌اید، آن را اینجا وارد کنید.</p><p>پس از تنظیم، generated file links این domain را ترجیح می‌دهند. اگر CDN ندارید، خالی بگذارید.</p><h3 id="چرا-upload-fail-می‌شود؟" tabindex="-1">چرا upload fail می‌شود؟ <a class="header-anchor" href="#چرا-upload-fail-می‌شود؟" aria-label="Permalink to &quot;چرا upload fail می‌شود؟&quot;">​</a></h3><p>اول این موارد را بررسی کنید:</p><ol><li>Endpoint شامل URL کامل <code>https://</code> باشد.</li><li>bucket name درست باشد.</li><li>Region با requirement provider هماهنگ باشد.</li><li>Access Key ID و Secret Access Key کامل copy شده باشند.</li><li>key برای target bucket دسترسی write داشته باشد.</li><li>provider به path-style access نیاز نداشته باشد، یا اگر نیاز دارد، path-style access enabled باشد.</li></ol><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>S3 Endpoint, Bucket, Region, Access Key و Secret Key را آماده کنید</span></span>
<span class="line"><span>-&gt; Upload Settings را باز کنید</span></span>
<span class="line"><span>-&gt; Add Channel</span></span>
<span class="line"><span>-&gt; S3 را انتخاب کنید</span></span>
<span class="line"><span>-&gt; Endpoint / Bucket / Region / Access Key / Secret Key را وارد کنید</span></span>
<span class="line"><span>-&gt; در صورت نیاز CDN domain وارد کنید</span></span>
<span class="line"><span>-&gt; path-style access را پیش‌فرض off بگذارید</span></span>
<span class="line"><span>-&gt; در صورت نیاز quota limit را enable کنید</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; یک test image upload کنید و نتیجه را بررسی کنید</span></span></code></pre></div>`,40)])])}const f=l(c,[["render",r]]);export{k as __pageData,f as default};
